"use client"

import { useState } from "react"
import Image from "next/image"
import { Button } from "@/components/atoms"
import { deleteLineItem, updateLineItem } from "@/lib/data/cart"
import { EnrichedCart, EnrichedCartItem } from "@/lib/services/cart-enrichment"
import { formatAmount } from "@/lib/helpers/money"
import { InventoryValidator } from "./InventoryValidator"

interface Props {
  enrichedCart: EnrichedCart
}

interface EnhancedCartItemProps {
  item: EnrichedCartItem
  currencyCode: string
}

function EnhancedCartItem({ item, currencyCode }: EnhancedCartItemProps) {
  const [updating, setUpdating] = useState(false)
  const [deleting, setDeleting] = useState(false)

  const handleUpdateQuantity = async (quantity: number) => {
    if (quantity <= 0) {
      return handleDelete()
    }
    
    setUpdating(true)
    try {
      await updateLineItem({ lineId: item.id, quantity })
    } catch (error) {
      console.error('Error updating cart item:', error)
    } finally {
      setUpdating(false)
    }
  }

  const handleDelete = async () => {
    setDeleting(true)
    try {
      await deleteLineItem(item.id)
    } catch (error) {
      console.error('Error deleting cart item:', error)
    } finally {
      setDeleting(false)
    }
  }

  const cardData = item.catalog_enrichment?.card
  const printData = item.catalog_enrichment?.print
  const gameData = item.catalog_enrichment?.game
  const setData = item.catalog_enrichment?.set
  const sellerData = item.seller_info

  return (
    <div className={`p-4 border rounded-lg bg-white ${deleting ? 'opacity-50' : ''}`}>
      <div className="flex gap-4">
        {/* Card Image */}
        <div className="flex-shrink-0">
          {printData?.image_small ? (
            <Image
              src={printData.image_small}
              alt={cardData?.name || item.title}
              width={80}
              height={112}
              className="rounded-lg border object-cover"
            />
          ) : (
            <div className="w-20 h-28 bg-gray-200 rounded-lg border flex items-center justify-center">
              <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
            </div>
          )}
        </div>

        {/* Card Details */}
        <div className="flex-grow">
          <div className="flex justify-between items-start">
            <div>
              <h3 className="font-semibold text-lg text-gray-900">
                {cardData?.name || item.title}
              </h3>
              
              {/* Game and Set Info */}
              <div className="flex items-center gap-2 mt-1">
                {gameData && (
                  <span className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded-full font-medium">
                    {gameData.name}
                  </span>
                )}
                {setData && (
                  <span className="text-sm text-gray-600">
                    {setData.name}
                  </span>
                )}
              </div>

              {/* Card Condition & Language */}
              <div className="flex items-center gap-3 mt-2">
                {item.catalog_enrichment?.condition && (
                  <div className="flex items-center gap-1">
                    <span className="text-xs text-gray-500">Condition:</span>
                    <span className="text-sm font-medium text-gray-900">
                      {item.catalog_enrichment.condition}
                    </span>
                  </div>
                )}
                {item.catalog_enrichment?.language && (
                  <div className="flex items-center gap-1">
                    <span className="text-xs text-gray-500">Language:</span>
                    <span className="text-sm font-medium text-gray-900">
                      {item.catalog_enrichment.language}
                    </span>
                  </div>
                )}
                {item.catalog_enrichment?.finish && item.catalog_enrichment.finish !== 'NORMAL' && (
                  <span className="px-2 py-1 bg-yellow-100 text-yellow-800 text-xs rounded-full">
                    {item.catalog_enrichment.finish}
                  </span>
                )}
              </div>

              {/* Seller Info */}
              {sellerData && (
                <div className="flex items-center gap-2 mt-2">
                  <span className="text-xs text-gray-500">Sold by:</span>
                  <div className="flex items-center gap-1">
                    <span className="text-sm font-medium text-gray-900">
                      {sellerData.name}
                    </span>
                    {sellerData.verified && (
                      <svg className="w-4 h-4 text-green-500" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                      </svg>
                    )}
                    {sellerData.type === 'consumer_seller' && (
                      <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 text-xs rounded">
                        Individual
                      </span>
                    )}
                    {sellerData.rating && (
                      <span className="text-sm text-gray-600">
                        ★ {sellerData.rating.toFixed(1)}
                      </span>
                    )}
                  </div>
                </div>
              )}
            </div>

            {/* Price and Actions */}
            <div className="text-right">
              <div className="text-lg font-bold text-gray-900">
                {formatAmount(item.total, currencyCode)}
              </div>
              {item.quantity > 1 && (
                <div className="text-sm text-gray-600">
                  {formatAmount(item.unit_price, currencyCode)} each
                </div>
              )}
            </div>
          </div>

          {/* Quantity Controls */}
          <div className="flex items-center justify-between mt-4">
            <div className="flex items-center gap-2">
              <span className="text-sm text-gray-600">Quantity:</span>
              <div className="flex items-center border rounded-lg">
                <button
                  onClick={() => handleUpdateQuantity(item.quantity - 1)}
                  disabled={updating || deleting}
                  className="p-2 hover:bg-gray-100 disabled:opacity-50"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                  </svg>
                </button>
                <span className="px-4 py-2 border-x text-center min-w-[50px]">
                  {item.quantity}
                </span>
                <button
                  onClick={() => handleUpdateQuantity(item.quantity + 1)}
                  disabled={updating || deleting}
                  className="p-2 hover:bg-gray-100 disabled:opacity-50"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                  </svg>
                </button>
              </div>
            </div>

            <button
              onClick={handleDelete}
              disabled={updating || deleting}
              className="text-red-600 hover:text-red-800 text-sm disabled:opacity-50"
            >
              {deleting ? 'Removing...' : 'Remove'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

function SellerGroup({ group, currencyCode }: { group: any, currencyCode: string }) {
  return (
    <div className="mb-6">
      {/* Seller Header */}
      <div className="flex items-center justify-between p-3 bg-gray-50 rounded-t-lg border-b">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2">
            <svg className="w-5 h-5 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
            </svg>
            <span className="font-medium text-gray-900">{group.seller_name}</span>
            {group.seller_type === 'consumer_seller' && (
              <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs rounded-full">
                Individual Seller
              </span>
            )}
          </div>
          {group.seller_rating && (
            <span className="text-sm text-gray-600">
              ★ {group.seller_rating.toFixed(1)}
            </span>
          )}
        </div>
        <div className="text-right">
          <div className="text-sm text-gray-600">
            {group.item_count} item{group.item_count !== 1 ? 's' : ''}
          </div>
          <div className="font-medium text-gray-900">
            {formatAmount(group.subtotal, currencyCode)}
          </div>
        </div>
      </div>

      {/* Seller Items */}
      <div className="border-x border-b rounded-b-lg">
        {group.items.map((item: EnrichedCartItem, index: number) => (
          <div key={item.id} className={index > 0 ? 'border-t' : ''}>
            <EnhancedCartItem item={item} currencyCode={currencyCode} />
          </div>
        ))}
      </div>
    </div>
  )
}

export function EnhancedCartItems({ enrichedCart }: Props) {
  if (!enrichedCart || enrichedCart.items.length === 0) {
    return (
      <div className="text-center py-12">
        <div className="w-24 h-24 mx-auto mb-4 bg-gray-200 rounded-lg flex items-center justify-center">
          <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4m0 0L7 13m0 0l-2.5 5M7 13l2.5 5m0 0H17M17 18a2 2 0 11-4 0 2 2 0 014 0zM9 18a2 2 0 11-4 0 2 2 0 014 0z" />
          </svg>
        </div>
        <h3 className="text-lg font-semibold text-gray-900 mb-2">Your cart is empty</h3>
        <p className="text-gray-600">Start building your collection by browsing our cards.</p>
      </div>
    )
  }

  // Currency code from first item (should be consistent across cart)
  const currencyCode = enrichedCart.items[0]?.total ? 'USD' : 'USD' // Fallback to USD

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold text-gray-900">Shopping Cart</h2>
        <span className="text-sm text-gray-600">
          {enrichedCart.totals.item_count} item{enrichedCart.totals.item_count !== 1 ? 's' : ''}
        </span>
      </div>

      {/* Inventory Validation */}
      <InventoryValidator items={enrichedCart.items} />

      {/* Show items grouped by seller */}
      {enrichedCart.seller_groups.length > 0 ? (
        enrichedCart.seller_groups.map((group) => (
          <SellerGroup
            key={group.seller_id}
            group={group}
            currencyCode={currencyCode}
          />
        ))
      ) : (
        /* Fallback: Show items without grouping */
        <div className="space-y-4">
          {enrichedCart.items.map((item) => (
            <EnhancedCartItem
              key={item.id}
              item={item}
              currencyCode={currencyCode}
            />
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import { useEffect, useState } from "react"
import { EnrichedCartItem } from "@/lib/services/cart-enrichment"

interface InventoryStatus {
  [variantId: string]: {
    available: boolean
    quantity?: number
    message?: string
  }
}

interface Props {
  items: EnrichedCartItem[]
  onInventoryUpdate?: (status: InventoryStatus) => void
  onQuantityAdjust?: (variantId: string, newQuantity: number) => void
  autoRefreshInterval?: number // milliseconds, default 120000 (2 min)
  enableAutoAdjust?: boolean
}

export function InventoryValidator({ 
  items, 
  onInventoryUpdate, 
  onQuantityAdjust,
  autoRefreshInterval = 120000,
  enableAutoAdjust = true
}: Props) {
  const [inventoryStatus, setInventoryStatus] = useState<InventoryStatus>({})
  const [loading, setLoading] = useState(false)
  const [lastCheck, setLastCheck] = useState<Date | null>(null)
  const [adjusting, setAdjusting] = useState<string[]>([]) // Track variants being adjusted

  const validateInventory = async () => {
    if (items.length === 0) return

    setLoading(true)
    try {
      const variantIds = items.map(item => item.variant_id)
      
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/commerce-integration/inventory/check`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            variantIds,
            useCache: true,
            includeLocations: false
          }),
          signal: AbortSignal.timeout(15000) // 15 second timeout
        }
      )

      if (!response.ok) {
        throw new Error('Failed to validate inventory')
      }

      const result = await response.json()
      
      if (result.success && result.data) {
        const status: InventoryStatus = {}
        
        // Check each cart item against inventory
        items.forEach(item => {
          const inventoryData = result.data[item.variant_id]
          
          if (inventoryData) {
            const availableQty = inventoryData.quantity || 0
            const available = availableQty >= item.quantity
            const canBackorder = inventoryData.can_backorder || false
            
            status[item.variant_id] = {
              available: available || canBackorder,
              quantity: availableQty,
              message: available 
                ? `${availableQty} available`
                : canBackorder 
                  ? `${availableQty} in stock (backorder available)`
                  : `Only ${availableQty} available (you have ${item.quantity} in cart)`
            }
          } else {
            status[item.variant_id] = {
              available: false,
              message: 'Inventory information unavailable'
            }
          }
        })
        
        setInventoryStatus(status)
        setLastCheck(new Date())
        onInventoryUpdate?.(status)
      }
    } catch (error) {
      console.error('Error validating inventory:', error)
      
      // Set all items as potentially unavailable on error
      const errorStatus: InventoryStatus = {}
      items.forEach(item => {
        errorStatus[item.variant_id] = {
          available: false,
          message: 'Unable to verify availability'
        }
      })
      setInventoryStatus(errorStatus)
    } finally {
      setLoading(false)
    }
  }

  // Validate inventory on mount and when items change
  useEffect(() => {
    validateInventory()
  }, [items.map(item => `${item.variant_id}-${item.quantity}`).join(',')])

  // Auto-refresh inventory at configurable interval
  useEffect(() => {
    if (autoRefreshInterval > 0) {
      const interval = setInterval(() => {
        validateInventory()
      }, autoRefreshInterval)

      return () => clearInterval(interval)
    }
  }, [items, autoRefreshInterval])

  // Handle automatic quantity adjustment
  const handleAutoAdjust = async (variantId: string, availableQuantity: number) => {
    if (!enableAutoAdjust || !onQuantityAdjust) return
    
    setAdjusting(prev => [...prev, variantId])
    
    try {
      await onQuantityAdjust(variantId, availableQuantity)
      // Refresh inventory after adjustment
      setTimeout(validateInventory, 500)
    } catch (error) {
      console.error('Failed to auto-adjust quantity:', error)
    } finally {
      setAdjusting(prev => prev.filter(id => id !== variantId))
    }
  }

  const hasInventoryIssues = Object.values(inventoryStatus).some(status => !status.available)
  const outOfStockItems = items.filter(item => !inventoryStatus[item.variant_id]?.available)

  if (loading && Object.keys(inventoryStatus).length === 0) {
    return (
      <div className="p-3 bg-gray-50 border border-gray-200 rounded-lg">
        <div className="flex items-center">
          <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-blue-600 mr-2"></div>
          <span className="text-sm text-gray-600">Checking inventory...</span>
        </div>
      </div>
    )
  }

  if (!hasInventoryIssues) {
    return (
      <div className="p-3 bg-green-50 border border-green-200 rounded-lg">
        <div className="flex items-center justify-between">
          <div className="flex items-center">
            <svg className="w-5 h-5 text-green-600 mr-2" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
            </svg>
            <span className="text-sm font-medium text-green-800">All items are in stock</span>
          </div>
          {lastCheck && (
            <span className="text-xs text-green-600">
              Last checked: {lastCheck.toLocaleTimeString()}
            </span>
          )}
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-3">
      {/* Overall inventory warning */}
      <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
        <div className="flex items-start">
          <svg className="w-5 h-5 text-yellow-600 mr-2 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
          </svg>
          <div className="flex-1">
            <h3 className="text-sm font-medium text-yellow-800">
              Inventory Issues Detected
            </h3>
            <p className="text-sm text-yellow-700 mt-1">
              {outOfStockItems.length} item{outOfStockItems.length !== 1 ? 's' : ''} may not be available in the requested quantity.
            </p>
          </div>
          <button
            onClick={validateInventory}
            disabled={loading}
            className="ml-2 text-yellow-600 hover:text-yellow-800 disabled:opacity-50"
            title="Refresh inventory status"
          >
            <svg className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        </div>
      </div>

      {/* Individual item issues */}
      <div className="space-y-2">
        {outOfStockItems.map(item => {
          const status = inventoryStatus[item.variant_id]
          const cardName = item.catalog_enrichment?.card?.name || item.title
          
          return (
            <div key={item.id} className="p-3 bg-red-50 border border-red-200 rounded-lg">
              <div className="flex items-start">
                <svg className="w-4 h-4 text-red-600 mr-2 mt-0.5" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
                <div className="flex-1">
                  <h4 className="text-sm font-medium text-red-800">{cardName}</h4>
                  <p className="text-sm text-red-700 mt-1">
                    {status?.message || 'Availability unknown'}
                  </p>
                  {status?.quantity !== undefined && status.quantity > 0 && (
                    <div className="mt-2 flex gap-2">
                      <button
                        onClick={() => handleAutoAdjust(item.variant_id, status.quantity!)}
                        disabled={adjusting.includes(item.variant_id) || !enableAutoAdjust}
                        className="text-xs bg-red-100 hover:bg-red-200 text-red-800 px-2 py-1 rounded disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1"
                      >
                        {adjusting.includes(item.variant_id) ? (
                          <>
                            <div className="animate-spin rounded-full h-3 w-3 border-b-2 border-red-600"></div>
                            Adjusting...
                          </>
                        ) : (
                          `Adjust to ${status.quantity} available`
                        )}
                      </button>
                      {status.quantity === 0 && (
                        <button
                          onClick={() => onQuantityAdjust?.(item.variant_id, 0)}
                          disabled={adjusting.includes(item.variant_id)}
                          className="text-xs bg-gray-100 hover:bg-gray-200 text-gray-800 px-2 py-1 rounded disabled:opacity-50"
                        >
                          Remove from cart
                        </button>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>
          )
        })}
      </div>

      {/* Real-time status footer */}
      <div className="flex items-center justify-between text-xs text-gray-500 pt-2 border-t border-gray-200">
        <div className="flex items-center gap-2">
          {loading && (
            <>
              <div className="animate-spin rounded-full h-3 w-3 border-b-2 border-blue-600"></div>
              <span>Checking inventory...</span>
            </>
          )}
          {lastCheck && !loading && (
            <span>Last updated: {lastCheck.toLocaleTimeString()}</span>
          )}
        </div>
        
        <div className="flex items-center gap-2">
          {autoRefreshInterval > 0 && (
            <span className="flex items-center gap-1">
              <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
              Auto-refresh: {Math.round(autoRefreshInterval / 1000)}s
            </span>
          )}
          <button
            onClick={validateInventory}
            disabled={loading}
            className="text-blue-600 hover:text-blue-800 disabled:opacity-50 underline"
          >
            Refresh now
          </button>
        </div>
      </div>
    </div>
  )
}

